import React, { useState, useEffect } from 'react';
import { ChevronDown, Globe } from 'lucide-react';
import api from '../services/api';
import { useTranslation } from '../utils/translations';

interface LanguageSelectorProps {
  onLanguageChange?: (language: string) => void;
}

const LanguageSelector: React.FC<LanguageSelectorProps> = ({ onLanguageChange }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [selectedLanguage, setSelectedLanguage] = useState('english');
  const [loading, setLoading] = useState(false);
  const { setLanguage } = useTranslation();

  const languages = [
    { code: 'english', name: 'English', flag: '🇺🇸' },
    { code: 'hindi', name: 'हिंदी', flag: '🇮🇳' },
    { code: 'marathi', name: 'मराठी', flag: '🇮🇳' },
    { code: 'konkani', name: 'कोंकणी', flag: '🇮🇳' }
  ];

  useEffect(() => {
    // Get user's preferred language from profile
    fetchUserLanguage();
  }, []);

  const fetchUserLanguage = async () => {
    try {
      const response = await api.get('/energy/user/profile');
      if (response.data.preferred_language) {
        setSelectedLanguage(response.data.preferred_language);
      }
    } catch (error) {
      console.error('Failed to fetch user language:', error);
    }
  };

  const handleLanguageSelect = async (languageCode: string) => {
    setLoading(true);
    try {
      await api.put('/energy/user/language', { language: languageCode });
      setSelectedLanguage(languageCode);
      setLanguage(languageCode);
      setIsOpen(false);

      if (onLanguageChange) {
        onLanguageChange(languageCode);
      }
    } catch (error) {
      console.error('Failed to update language:', error);
    } finally {
      setLoading(false);
    }
  };

  const selectedLang = languages.find(lang => lang.code === selectedLanguage) || languages[0];

  return (
    <div className="relative">
      <button
        onClick={() => setIsOpen(!isOpen)}
        disabled={loading}
        className="flex items-center space-x-2 px-3 py-2 text-sm border border-gray-300 rounded-lg hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-colors disabled:opacity-50"
      >
        <Globe className="w-4 h-4 text-gray-600" />
        <span className="text-gray-700">{selectedLang.flag}</span>
        <span className="text-gray-700 hidden sm:inline">{selectedLang.name}</span>
        <ChevronDown className={`w-4 h-4 text-gray-600 transition-transform ${isOpen ? 'rotate-180' : ''}`} />
      </button>

      {isOpen && (
        <div className="absolute top-full left-0 mt-1 w-48 bg-white border border-gray-200 rounded-lg shadow-lg z-[9999]">
          {languages.map((language) => (
            <button
              key={language.code}
              onClick={() => handleLanguageSelect(language.code)}
              disabled={loading}
              className={`w-full px-4 py-3 text-left hover:bg-gray-50 flex items-center space-x-3 transition-colors disabled:opacity-50 ${
                selectedLanguage === language.code ? 'bg-blue-50 text-blue-700' : 'text-gray-700'
              } ${language === languages[0] ? 'rounded-t-lg' : ''} ${
                language === languages[languages.length - 1] ? 'rounded-b-lg' : ''
              }`}
            >
              <span className="text-lg">{language.flag}</span>
              <span className="font-medium">{language.name}</span>
              {selectedLanguage === language.code && (
                <span className="ml-auto text-blue-600">✓</span>
              )}
            </button>
          ))}
        </div>
      )}

      {isOpen && (
        <div
          className="fixed inset-0 z-[9998]"
          onClick={() => setIsOpen(false)}
        />
      )}
    </div>
  );
};

export default LanguageSelector;
